import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void classic() {
        // "abc" is the longest window before a repeat
        assertEquals(3, new Solution().lengthOfLongestSubstring("abcabcbb"));
    }

    @Test
    void allSame() {
        assertEquals(1, new Solution().lengthOfLongestSubstring("bbbbb"));
    }

    @Test
    void mixedWindow() {
        // "wke" is the longest window
        assertEquals(3, new Solution().lengthOfLongestSubstring("pwwkew"));
    }

    @Test
    void empty() {
        assertEquals(0, new Solution().lengthOfLongestSubstring(""));
    }

    @Test
    void singleChar() {
        assertEquals(1, new Solution().lengthOfLongestSubstring("a"));
    }

    @Test
    void allUnique() {
        assertEquals(6, new Solution().lengthOfLongestSubstring("abcdef"));
    }

    @Test
    void repeatAtEnd() {
        // "abcde" then repeat — longest is 5
        assertEquals(5, new Solution().lengthOfLongestSubstring("abcdeabcde"));
    }
}
